content.problemStatement:
There are **N** servers which you have to place in **N** slots. Slots and servers are numbered from **1** to **N**.

A distance between slots **i** and **j** is **|i - j|**. There are **M** pairs of servers that should be connected by wire. You are to place all the servers in the slots so the total wire length is minimized. 

&nbsp;

code.C:
#include <stdio.h>
#include <stdlib.h>

int compare(const void *a, const void *b) {
    return *(int*)a - *(int*)b;
}

int calculate_wire_length(int *servers, int *pairs, int n, int m) {
    int total_length = 0;
    for (int i = 0; i < m; i++) {
        int a = pairs[i * 2] - 1;
        int b = pairs[i * 2 + 1] - 1;
        total_length += abs(servers[a] - servers[b]);
    }
    return total_length;
}

void swap(int *a, int *b) {
    int temp = *a;
    *a = *b;
    *b = temp;
}

void permute(int *servers, int *pairs, int n, int m, int start, int *min_length) {
    if (start == n) {
        int length = calculate_wire_length(servers, pairs, n, m);
        if (length < *min_length) {
            *min_length = length;
        }
    } else {
        for (int i = start; i < n; i++) {
            swap(&servers[start], &servers[i]);
            permute(servers, pairs, n, m, start + 1, min_length);
            swap(&servers[start], &servers[i]);
        }
    }
}

int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        int n, m;
        scanf("%d %d", &n, &m);
        int *servers = (int*)malloc(n * sizeof(int));
        int *pairs = (int*)malloc(m * 2 * sizeof(int));
        for (int i = 0; i < n; i++) {
            servers[i] = i + 1;
        }
        for (int i = 0; i < m * 2; i++) {
            scanf("%d", &pairs[i]);
        }
        int min_length = 1000000;
        permute(servers, pairs, n, m, 0, &min_length);
        printf("%d\n", min_length);
        free(servers);
        free(pairs);
    }
    return 0;
}

