import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int t = scanner.nextInt();
        while (t-- > 0) {
            int n = scanner.nextInt();
            int m = scanner.nextInt();
            int[] servers = new int[n];
            int[] pairs = new int[m * 2];
            for (int i = 0; i < n; i++) {
                servers[i] = i + 1;
            }
            for (int i = 0; i < m * 2; i++) {
                pairs[i] = scanner.nextInt();
            }
            int min_length = 1000000;
            permute(servers, pairs, n, m, 0, min_length);
            System.out.println(min_length);
        }
    }

    public static void permute(int[] servers, int[] pairs, int n, int m, int start, int min_length) {
        if (start == n) {
            int length = calculate_wire_length(servers, pairs, n, m);
            if (length < min_length) {
                min_length = length;
            }
        } else {
            for (int i = start; i < n; i++) {
                swap(servers, start, i);
                permute(servers, pairs, n, m, start + 1, min_length);
                swap(servers, start, i);
            }
        }
    }

    public static void swap(int[] arr, int i, int j) {
        int temp = arr[i];
        arr[i] = arr[j];
        arr[j] = temp;
    }

    public static int calculate_wire_length(int[] servers, int[] pairs, int n, int m) {
        int total_length = 0;
        for (int i = 0; i < m; i++) {
            int a = pairs[i * 2] - 1;
            int b = pairs[i * 2 + 1] - 1;
            total_length += Math.abs(servers[a] - servers[b]);
        }
        return total_length;
    }
}

code.Python3:
import itertools

def calculate_wire_length(servers, pairs):
    total_length = 0
    for a, b in zip(pairs[::2], pairs[1::2]):
        total_length += abs(servers[a - 1] - servers[b - 1])
    return total_length

def main():
    t = int(input())
    for _ in range(t):
        n, m = map(int, input().split())
        pairs = list(map(int, input().split()))
        min_length = float('inf')
        for servers in itertools.permutations(range(1, n + 1)):
            length = calculate_wire_length(servers, pairs)
            if length < min_length:
                min_length = length
        print(min_length)

if __name__ == '__main__':
    main()

